parameters.jsCode:
const item = $input.item.json;

const safe = (val) => {
  if (val === null || val === undefined || val === '') return '--';
  return String(val).trim();
};

const body = item.body ?? item;

const name    = safe(body.fullName ?? body.full_name ?? body.name ?? '');
const email   = safe(body.email ?? body.client_email ?? '');
const address = safe(body.address ?? body.street_address ?? '');
const city    = safe(body.city ?? '');
const state   = safe(body.state ?? '');
const zip     = safe(body.zip ?? body.zip_code ?? '');
const role    = safe(body.role ?? '');
const phone   = safe(body.phone ?? '');

const fullAddress = [address, city, state, zip]
  .filter(v => v && v !== '--')
  .join(', ');

return [{
  json: {
    intake: { name, email, phone, role, address, city, state, zip, fullAddress }
  }
}];

const safe = (val) => { if (val === null || val === undefined || val === '' || val === 'N/A') return '—'; return String(val).trim(); };
const safeNum = (val) => { const n = parseFloat(val); return isNaN(n) ? '—' : n; };
const fmt$ = (val) => { const n = parseFloat(val); return isNaN(n) ? '—' : '$' + Math.round(n).toLocaleString(); };

const intake = $('Normalize Intake').item.json.intake ?? {};
const propArr = $('Property Lookup').item.json ?? [];
const prop = Array.isArray(propArr) ? (propArr[0] ?? {}) : (propArr ?? {});
const val = $('Valuation Lookup').item.json ?? {};
const nwsForecast = ($('NWS Forecast').item.json?.properties?.periods) ?? [];

// ── FEMA FLOOD ───────────────────────────────────────────────────────────
const femaFeatures = $('FEMA Flood Zone').item.json?.features ?? [];
const femaAttrs = femaFeatures[0]?.attributes ?? {};
const floodZone = safe(femaAttrs.FLD_ZONE);
const floodHighRisk = femaAttrs.SFHA_TF === 'T';
const floodSubtype = safe(femaAttrs.ZONE_SUBTY);
const floodLabel = floodHighRisk ? 'HIGH RISK — SFHA' : (floodZone === 'X' ? 'Minimal Hazard' : floodZone === '—' ? 'Unknown' : 'Moderate Risk');

// ── COMPARABLE SALES ────────────────────────────────────────────────────
const compsData = $('RentCast Comps').item.json ?? {};
const comps = (compsData.comparables ?? []).slice(0, 10).map(c => ({
  address: safe(c.formattedAddress),
  price: c.price ? fmt$(c.price) : '—',
  rawPrice: c.price || 0,
  sqft: c.squareFootage ? Number(c.squareFootage).toLocaleString() + ' sqft' : '—',
  beds: safe(c.bedrooms),
  baths: safe(c.bathrooms),
  distance: c.distance ? c.distance.toFixed(2) + ' mi' : '—',
  lat: c.latitude || null,
  lon: c.longitude || null,
  correlation: c.correlation ? (c.correlation * 100).toFixed(0) + '%' : '—'
}));
const avm = compsData.price ? fmt$(compsData.price) : '—';
const avmLow = compsData.priceRangeLow ? fmt$(compsData.priceRangeLow) : '—';
const avmHigh = compsData.priceRangeHigh ? fmt$(compsData.priceRangeHigh) : '—';

// ── CENSUS DEMOGRAPHICS ─────────────────────────────────────────────────
let demographics = {};
try {
  const acsRaw = $('Census ACS').item.json;
  if (Array.isArray(acsRaw) && acsRaw.length >= 2) {
    const headers = acsRaw[0];
    const values = acsRaw[1];
    const get = (key) => { const i = headers.indexOf(key); return i >= 0 ? values[i] : null; };
    const pop = parseFloat(get('B01003_001E'));
    const unemployed = parseFloat(get('B23025_005E'));
    const ownerOcc = parseFloat(get('B25003_002E'));
    const renterOcc = parseFloat(get('B25003_003E'));
    const movers = parseFloat(get('B07003_004E'));
    const bach = parseFloat(get('B15003_022E'));
    const masters = parseFloat(get('B15003_023E'));
    demographics = {
      medianIncome: fmt$(get('B19013_001E')),
      population: pop ? pop.toLocaleString() : '—',
      medianHomeValue: fmt$(get('B25077_001E')),
      ownerOccupied: ownerOcc && renterOcc ? Math.round(ownerOcc/(ownerOcc+renterOcc)*100) + '%' : '—',
      renterOccupied: ownerOcc && renterOcc ? Math.round(renterOcc/(ownerOcc+renterOcc)*100) + '%' : '—',
      unemploymentRate: (unemployed && pop) ? (unemployed/pop*100).toFixed(1) + '%' : '—',
      mobilityRate: (movers && pop) ? Math.round(movers/pop*100) + '% moved in past year' : '—',
      collegePct: (bach && masters && pop) ? Math.round((bach+masters)/pop*100) + '%' : '—',
      neighborhoodTrend: movers && pop && (movers/pop) > 0.15 ? 'High Mobility — Active Turnover' : movers && pop && (movers/pop) > 0.08 ? 'Moderate Mobility' : 'Stable Established Neighborhood'
    };
  }
} catch(e) { demographics = {}; }

// ── PROPERTY DATA ───────────────────────────────────────────────────────
let matchedAddress = '—';
if (prop.formattedAddress) matchedAddress = prop.formattedAddress;
else if (prop.addressLine1) matchedAddress = [prop.addressLine1, prop.city, prop.state, prop.zipCode].filter(Boolean).join(', ');

const propertyType = safe(prop.propertyType);
const yearBuilt = safe(prop.yearBuilt);
const beds = safe(prop.bedrooms);
const baths = safe(prop.bathrooms);
const sqft = safe(prop.squareFootage);
const lotSize = safe(prop.lotSize);
const lastSaleDate = safe(prop.lastSaleDate);
const lastSalePrice = prop.lastSalePrice ? fmt$(prop.lastSalePrice) : '—';
const apn = safe(prop.assessorID ?? prop.apn);

const hasValuation = val && (val.price || val.priceRangeHigh);
const marketValue = hasValuation ? fmt$(val.price) : avm;
const valLow = hasValuation ? fmt$(val.priceRangeLow) : avmLow;
const valHigh = hasValuation ? fmt$(val.priceRangeHigh) : avmHigh;
const valConf = hasValuation ? safe(val.confidence) : 'Derived from Comps';

// ── WEATHER ─────────────────────────────────────────────────────────────
const wp1 = nwsForecast[0] ?? {};
const wp2 = nwsForecast[1] ?? {};
const weatherSummary = wp1.shortForecast ? `${wp1.name}: ${wp1.shortForecast}, ${wp1.temperature}°${wp1.temperatureUnit}` : '—';

// ── DATA QUALITY SCORE ──────────────────────────────────────────────────

// ── FBI CRIME DATA ──────��───────────────────────────────────────────────
let crimeData = {};
try {
  crimeData = $('FBI Crime Data').item.json || { available: false };
} catch(e) { crimeData = { available: false }; }

// ── BUILDZOOM PERMITS ───────────────────────────────────────────────────
let permitData = {};
try {
  const bzRaw = $('BuildZoom Permits').item.json;
  if (bzRaw && bzRaw.permits) {
    const permits = bzRaw.permits.slice(0, 10);
    permitData = {
      total: bzRaw.total_count || permits.length,
      recent: permits.map(p => ({
        description: p.description || p.permit_type || '—',
        date: p.filed_date || p.issue_date || '—',
        value: p.value ? '$' + Number(p.value).toLocaleString() : '—',
        status: p.status || '—'
      })),
      available: true
    };
  }
} catch(e) { permitData = { available: false }; }

// ── SPOTCRIME ──────────────────────────────────────────────────────────
let crimeIncidents = {};
try {
  const scRaw = $('SpotCrime').item.json;
  if (scRaw && Array.isArray(scRaw.crimes)) {
    const crimes = scRaw.crimes;
    const sixMonthsAgo = new Date(); sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
    const recent = crimes.filter(c => c.date && new Date(c.date) > sixMonthsAgo);
    const byType = {};
    recent.forEach(c => { const t = c.type || 'Other'; byType[t] = (byType[t] || 0) + 1; });
    crimeIncidents = {
      totalLast6Mo: recent.length,
      monthlyAvg: (recent.length / 6).toFixed(1),
      byType,
      radius: '0.25 mi',
      available: true
    };
  }
} catch(e) { crimeIncidents = { available: false }; }

let score = 0;
if (intake.email && intake.email !== '—') score += 10;
if (matchedAddress !== '—') score += 15;
if (apn !== '—') score += 10;
if (propertyType !== '—') score += 10;
if (yearBuilt !== '—') score += 5;
if (beds !== '—') score += 5;
if (baths !== '—') score += 5;
if (sqft !== '—') score += 10;
if (hasValuation || avm !== '—') score += 15;
if (comps.length > 0) score += 10;
if (demographics.medianIncome) score += 5;
if (floodZone !== '—') score += 5;

let rating = 'C';
if (score >= 90) rating = 'A+'; else if (score >= 85) rating = 'A';
else if (score >= 80) rating = 'A-'; else if (score >= 75) rating = 'B+';
else if (score >= 70) rating = 'B'; else if (score >= 65) rating = 'B-'; else if (score >= 60) rating = 'C+';
let confidence = 'Low';
if (score >= 85) confidence = 'High'; else if (score >= 70) confidence = 'Moderate';

const normalized = {
  client: { name: safe(intake.name), email: safe(intake.email) },
  subject: { requestedAddress: intake.fullAddress ?? '—', matchedAddress, city: safe(prop.city ?? intake.city), state: safe(prop.state ?? intake.state), zip: safe(prop.zipCode ?? intake.zip), lat: safeNum(prop.latitude), lon: safeNum(prop.longitude) },
  ids: { apn, propertyId: safe(prop.id) },
  property: { propertyType, yearBuilt, beds, baths, sqft, lotSize },
  sale: { lastSaleDate, lastSalePrice },
  valuation: { marketValue, low: valLow, high: valHigh, confidence: valConf },
  comps,
  flood: { zone: floodZone, highRisk: floodHighRisk, label: floodLabel, subtype: floodSubtype },
  demographics,
  weather: { summary: weatherSummary, period1: wp1.shortForecast || '—', period2: wp2.shortForecast || '—' },
  crime: crimeData,
  permits: permitData,
  incidents: crimeIncidents
};

return [{ json: { normalized, score, rating, confidence } }];

const prev = $('Merge Normalize Score').item.json;
const normalized = prev.normalized;
const score = prev.score;
const rating = prev.rating;
const confidence = prev.confidence;
let narrative = {};
try {
  const rawContent = $('OpenAI Narrative').item.json && $('OpenAI Narrative').item.json.content;
  let rawText = '';
  if (Array.isArray(rawContent)) { rawText = rawContent.map(b => b.text || '').join(''); } else if (typeof rawContent === 'string') { rawText = rawContent; }
  rawText = rawText.replace(/```json|```/g, '').trim();
  narrative = JSON.parse(rawText);
} catch(e) {
  narrative = { executiveSummary: 'Property data collected and normalized for review.', sellerAngle: 'Seller positioning analysis pending.', buyerAngle: 'Buyer analysis pending. Core metrics captured.', investmentAngle: 'Investment analysis pending valuation confirmation.', dataQualityNote: 'Data completeness score: ' + score + '/100. Some fields may require manual verification.', wouldWeBuyIt: score >= 75 ? 'Maybe' : 'Needs Review', wouldWeBuyItReason: 'Review normalized record directly.' };
}
const n = normalized;
const cl = n.client;
const sub = n.subject;
const ids = n.ids;
const pr = n.property;
const sl = n.sale;
const vl = n.valuation;
const wx = n.weather;
const ratingColors = { 'A+': '#2D6A4F', 'A': '#2D6A4F', 'A-': '#40916C', 'B+': '#74C69D', 'B': '#95D5B2', 'B-': '#B7E4C7', 'C+': '#C9A96E', 'C': '#A07850' };
const ratingColor = ratingColors[rating] || '#888';
const confColor = confidence === 'High' ? '#2D6A4F' : confidence === 'Moderate' ? '#C9A96E' : '#A07850';
const buyColors = { 'Yes': '#2D6A4F', 'Maybe': '#C9A96E', 'Needs Review': '#A07850' };
const buyItColor = buyColors[narrative.wouldWeBuyIt] || '#888';
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const sqftDisplay = pr.sqft !== '—' ? Number(pr.sqft).toLocaleString() + ' sq ft' : '—';
const lotDisplay = pr.lotSize !== '—' ? Number(pr.lotSize).toLocaleString() + ' sq ft' : '—';
const latlon = (sub.lat !== '—' && sub.lon !== '—') ? (sub.lat + ', ' + sub.lon) : '—';
const displayAddress = sub.matchedAddress !== '—' ? sub.matchedAddress : sub.requestedAddress;
const wx2line = wx.period2 !== '—' ? '<p style="margin:8px 0 0 0;font-family:Georgia,serif;font-size:13px;color:#9E8E7E;line-height:1.6;">' + wx.period2 + '</p>' : '';

// ── COMPARABLE SALES ────────────────────────────────────────────────────
const compsRows = (n.comps ?? []).map(c =>
  `<tr>
    <td style="padding:8px 0;border-bottom:1px solid #EDE8E0;font-family:Georgia,serif;font-size:12px;color:#2C2825;">${c.address}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #EDE8E0;font-family:Georgia,serif;font-size:13px;color:#2C2825;text-align:right;font-weight:bold;">${c.price}</td>
    <td style="padding:8px 0;border-bottom:1px solid #EDE8E0;font-family:Georgia,serif;font-size:12px;color:#9E8E7E;text-align:right;">${c.sqft}</td>
    <td style="padding:8px 0 8px 12px;border-bottom:1px solid #EDE8E0;font-family:Georgia,serif;font-size:12px;color:#9E8E7E;text-align:right;">${c.distance}</td>
  </tr>`
).join('');
const compsSection = compsRows ? `<tr><td style="padding:0 48px;"><hr style="border:none;border-top:1px solid #EDE8E0;margin:0;"/></td></tr><tr><td style="padding:28px 48px 0 48px;"><p style="margin:0 0 16px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Comparable Sales</p><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><th style="font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;text-align:left;padding-bottom:8px;">Address</th><th style="font-family:Georgia,serif;font-size:10px;color:#9E8E7E;text-transform:uppercase;text-align:right;padding-bottom:8px;padding-right:12px;">Price</th><th style="font-family:Georgia,serif;font-size:10px;color:#9E8E7E;text-transform:uppercase;text-align:right;padding-bottom:8px;">Size</th><th style="font-family:Georgia,serif;font-size:10px;color:#9E8E7E;text-transform:uppercase;text-align:right;padding-bottom:8px;padding-left:12px;">Dist</th></tr>${compsRows}</table></td></tr>` : '';

// ── NEIGHBORHOOD DEMOGRAPHICS ───────────────────────────────────────────
const demo = n.demographics ?? {};
const demoSection = demo.medianIncome ? `<tr><td style="padding:0 48px;"><hr style="border:none;border-top:1px solid #EDE8E0;margin:0;"/></td></tr><tr><td style="padding:28px 48px 0 48px;"><p style="margin:0 0 16px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Neighborhood Profile</p><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="33%" style="padding-bottom:14px;vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Median Income</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:15px;color:#2C2825;">${demo.medianIncome}</p></td><td width="33%" style="padding-bottom:14px;vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Median Home Value</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:15px;color:#2C2825;">${demo.medianHomeValue}</p></td><td width="33%" style="padding-bottom:14px;vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Owner / Renter</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:15px;color:#2C2825;">${demo.ownerOccupied} / ${demo.renterOccupied}</p></td></tr><tr><td colspan="3"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Neighborhood Trend</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:14px;color:#2C2825;">${demo.neighborhoodTrend} &nbsp;·&nbsp; ${demo.mobilityRate}</p></td></tr></table></td></tr>` : '';

// ── RISK PROFILE ────────────────────────────────────────────────────────
const flood = n.flood ?? {};
const floodRiskColor = flood.highRisk ? '#A07850' : '#2D6A4F';
const riskSection = flood.zone ? `<tr><td style="padding:0 48px;"><hr style="border:none;border-top:1px solid #EDE8E0;margin:0;"/></td></tr><tr><td style="padding:28px 48px 0 48px;"><p style="margin:0 0 12px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Risk Profile</p><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#F0EBE3;"><tr><td style="padding:20px 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="50%" style="vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">FEMA Flood Zone</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:18px;color:${floodRiskColor};">Zone ${flood.zone}</p><p style="margin:2px 0 0 0;font-family:Georgia,serif;font-size:12px;color:#9E8E7E;">${flood.label}</p></td><td width="50%" style="vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:10px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Special Flood Hazard Area</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:18px;color:${floodRiskColor};">${flood.highRisk ? 'Yes — SFHA' : 'No'}</p><p style="margin:2px 0 0 0;font-family:Georgia,serif;font-size:12px;color:#9E8E7E;">${flood.subtype !== '—' ? flood.subtype : 'Standard zone determination'}</p></td></tr></table></td></tr></table></td></tr>` : '';

const htmlReport = '<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>Property DNA Report</title></head><body style="margin:0;padding:0;background-color:#F7F4EF;font-family:Georgia,serif;color:#2C2825;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#F7F4EF;"><tr><td align="center" style="padding:40px 20px;"><table width="640" cellpadding="0" cellspacing="0" border="0" style="max-width:640px;background-color:#FFFFFF;"><tr><td style="background-color:#2C2825;padding:48px 48px 36px 48px;"><p style="margin:0 0 6px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Confidential Analysis</p><h1 style="margin:0 0 8px 0;font-family:Georgia,serif;font-size:28px;font-weight:400;color:#F7F4EF;line-height:1.2;">Property DNA Report</h1><p style="margin:0;font-family:Georgia,serif;font-size:14px;color:#9E8E7E;line-height:1.6;">' + displayAddress + '</p><p style="margin:16px 0 0 0;font-family:Georgia,serif;font-size:12px;color:#9E8E7E;">Prepared for ' + (cl.name !== '—' ? cl.name : 'Valued Client') + ' &nbsp;&middot;&nbsp; ' + today + '</p></td></tr><tr><td style="padding:0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="background-color:#F0EBE3;padding:20px 48px;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td><p style="margin:0;font-family:Georgia,serif;font-size:11px;letter-spacing:2px;color:#9E8E7E;text-transform:uppercase;">Data Quality Score</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:32px;font-weight:400;color:#2C2825;">' + score + '<span style="font-size:16px;color:#9E8E7E;">/100</span></p></td><td align="right"><span style="display:inline-block;background-color:' + ratingColor + ';color:#FFFFFF;font-family:Georgia,serif;font-size:22px;padding:8px 20px;">' + rating + '</span></td><td align="right" style="padding-left:12px;"><span style="display:inline-block;background-color:' + confColor + ';color:#FFFFFF;font-family:Georgia,serif;font-size:12px;letter-spacing:1px;padding:6px 14px;text-transform:uppercase;">' + confidence + ' Confidence</span></td></tr></table></td></tr></table></td></tr><tr><td style="padding:0 48px;"><hr style="border:none;border-top:1px solid #EDE8E0;margin:0;"/></td></tr><tr><td style="padding:36px 48px 24px 48px;"><p style="margin:0 0 10px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Executive Summary</p><p style="margin:0;font-family:Georgia,serif;font-size:16px;color:#2C2825;line-height:1.8;">' + narrative.executiveSummary + '</p></td></tr><tr><td style="padding:0 48px 32px 48px;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#F0EBE3;"><tr><td style="padding:20px 24px;"><p style="margin:0 0 4px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:2px;color:#9E8E7E;text-transform:uppercase;">Would We Buy It?</p><p style="margin:0 0 8px 0;font-family:Georgia,serif;font-size:20px;color:' + buyItColor + ';">' + (narrative.wouldWeBuyIt || '—') + '</p><p style="margin:0;font-family:Georgia,serif;font-size:13px;color:#2C2825;line-height:1.6;">' + (narrative.wouldWeBuyItReason || '—') + '</p></td></tr></table></td></tr><tr><td style="padding:0 48px;"><hr style="border:none;border-top:1px solid #EDE8E0;margin:0;"/></td></tr><tr><td style="padding:32px 48px 0 48px;"><p style="margin:0 0 20px 0;font-family:Georgia,serif;font-size:11px;letter-spacing:3px;color:#C9A96E;text-transform:uppercase;">Property Vitals</p><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="50%" style="padding-bottom:16px;vertical-align:top;"><p style="margin:0;font-family:Georgia,serif;font-size:11px;letter-spacing:1px;color:#9E8E7E;text-transform:uppercase;">Type</p><p style="margin:4px 0 0 0;font-family:Georgia,serif;font-size:15px;color:#2C2825;">' + pr.propertyTy