const intake = $('Normalize Intake').item.json.intake || {};
const stateAbbr = (intake.state || 'CA').trim().toUpperCase();
const city = (intake.city || '').trim().toLowerCase();
const FBI_KEY = 'jsrSjzlIKcYOCUxhfknllkFP0YkYaTyvWLcTiIgF';

let crimeStats = { available: false, city: intake.city, state: stateAbbr };

try {
  // Step 1: find agency ORI for this city
  const agencyResp = await this.helpers.request({
    method: 'GET',
    url: `https://api.usa.gov/crime/fbi/cde/agency/byStateAbbr/${stateAbbr}?API_KEY=${FBI_KEY}`,
    headers: { Accept: 'application/json' }
  });
  const agencyData = JSON.parse(agencyResp);

  let matchedOri = null;
  for (const [county, agencies] of Object.entries(agencyData)) {
    for (const agency of (agencies || [])) {
      if (agency.agency_name && agency.agency_name.toLowerCase().includes(city) && agency.agency_type_name === 'City') {
        matchedOri = agency.ori;
        crimeStats.agencyName = agency.agency_name;
        crimeStats.agencyOri = matchedOri;
        break;
      }
    }
    if (matchedOri) break;
  }

  if (!matchedOri) {
    crimeStats.available = false;
    crimeStats.note = 'No matching police agency found for ' + city;
    return [{ json: crimeStats }];
  }

  // Step 2: get violent crime + property crime rates
  const from = '01-2022';
  const to = '12-2022';

  const [violentResp, propertyResp] = await Promise.all([
    this.helpers.request({ method: 'GET', url: `https://api.usa.gov/crime/fbi/cde/summarized/agency/${matchedOri}/violent-crime?from=${from}&to=${to}&API_KEY=${FBI_KEY}` }),
    this.helpers.request({ method: 'GET', url: `https://api.usa.gov/crime/fbi/cde/summarized/agency/${matchedOri}/property-crime?from=${from}&to=${to}&API_KEY=${FBI_KEY}` })
  ]);

  const violent = JSON.parse(violentResp);
  const property = JSON.parse(propertyResp);

  // Extract annual rates (per 100K population)
  const extractAnnualRate = (data) => {
    const rates = data?.offenses?.rates;
    if (!rates) return null;
    // Get the city-specific key (not CA state avg)
    const cityKey = Object.keys(rates).find(k => !k.toLowerCase().includes('california') && !k.toLowerCase().includes('state'));
    const stateKey = Object.keys(rates).find(k => k.toLowerCase().includes('california') || k.toLowerCase().includes('state'));
    const src = rates[cityKey] || rates[stateKey];
    if (!src) return null;
    const values = Object.values(src).map(Number).filter(v => !isNaN(v));
    return values.length ? (values.reduce((a, b) => a + b, 0) / values.length).toFixed(1) : null;
  };

  crimeStats = {
    available: true,
    city: intake.city,
    state: stateAbbr,
    agencyName: crimeStats.agencyName,
    agencyOri: matchedOri,
    year: '2022',
    violentCrimeRatePer100k: extractAnnualRate(violent),
    propertyCrimeRatePer100k: extractAnnualRate(property),
    source: 'FBI UCR / NIBRS',
    note: 'Rates per 100K population'
  };

} catch(e) {
  crimeStats.error = e.message;
  crimeStats.available = false;
}

return [{ json: crimeStats }];
